CODE_EXAMPLE:
public class LoadBalancer {
  private List<string> servers = new List<string> { "server1", "server2", "server3" };
  private int currentIndex = 0;

  public string GetServer() {
    string server = servers[currentIndex % servers.Count];
    currentIndex++;
    return server;
  }
}

UNIT_TEST_EXAMPLE:
[TestMethod]
public void GetServer_DistributesRoundRobin() {
  var lb = new LoadBalancer();
  Assert.AreEqual("server1", lb.GetServer());
  Assert.AreEqual("server2", lb.GetServer());
  Assert.AreEqual("server3", lb.GetServer());
  Assert.AreEqual("server1", lb.GetServer());
}

[TestMethod]
public void GetServer_ReturnsValidServer() {
  var lb = new LoadBalancer();
  var server = lb.GetServer();
  Assert.IsNotNull(server);
  Assert.IsTrue(server.StartsWith("server"));
}
